// Lấy danh sách events từ node Postgres phía trước
const events = $input.all();

// Lấy dữ liệu từ Webhook đầu vào
const inputData = $input.first().json;
const body = inputData.body || {};

// Lấy date từ body, nếu không có thì lấy ngày hiện tại
const currentDate = body.date || new Date().toISOString().split('T')[0];
const sku = body.SKU || "Unknown";

// 1. Lọc các event đang active dựa trên currentDate
const activeEvents = events.filter((event) => {
  const data = event.json;

  const startDateStr = String(data.start_date || data.startDate || '');
  const endDateStr   = String(data.end_date   || data.endDate   || '');

  if (!startDateStr || !endDateStr) return false;

  const startDate = new Date(startDateStr);
  const endDate   = new Date(endDateStr);
  const today     = new Date(currentDate);

  startDate.setHours(0, 0, 0, 0);
  endDate.setHours(23, 59, 59, 999);
  today.setHours(0, 0, 0, 0);

  return today >= startDate && today <= endDate;
});

// 2. Tìm event có mức giảm giá tốt nhất
let bestEvent = null;

for (const item of activeEvents) {
  const currentDiscount = item.json.discount_percent || 0;
  const bestDiscount = bestEvent ? (bestEvent.json.discount_percent || 0) : -1;

  if (currentDiscount > bestDiscount) {
    bestEvent = item;
  }
}

// 3. Trả về kết quả cho node IF "Has Event?"
return [{
  json: {
    sku: sku,
    hasEvent: !!bestEvent,
    event: bestEvent ? bestEvent.json : null,
    currentDate: currentDate,
    activeEventsCount: activeEvents.length,
    bestDiscount: bestEvent ? (bestEvent.json.discount_percent || 0) : 0
  }
}];

// Mode: Run Once for All Items
return $input.all().map(item => {
  const data = item.json;
  const body = data.body || {};
  const sku = body.SKU || data.sku || "Unknown";

  // Nếu không có event, trả về giá gốc (lấy từ currentPrice trong body hoặc 0)
  const originalPrice = body.currentPrice || data.currentPrice || 0;

  return {
    json: {
      sku: sku,
      hasEvent: false,
      eventDiscount: false,
      eventInfo: null,
      display_price: originalPrice,
      discount_percent: 0,
      isVIP: false,
      member_level: 'none'
    }
  };
});

// Lấy dữ liệu từ node trước (Check Event Logic)
const inputData = $input.first().json;
const body = inputData.body || {};

// Lấy thông tin event
const event = inputData.event;

// Lấy danh sách tất cả sản phẩm
const allProducts = $input.all().map(item => item.json);

// Nếu không có event, trả về danh sách sản phẩm không đổi
if (!event || !inputData.hasEvent) {
  return allProducts.map(product => ({
    json: {
      sku: product.sku,
      hasEvent: false,
      eventDiscount: false,
      eventInfo: null,
      display_price: product.current_price,
      discount_percent: 0,
      isVIP: false,
      member_level: 'none'
    }
  }));
}

// Tính toán mức giảm giá
const discountPercent = event.discount_percent || 0;

// Áp dụng discount cho TẤT CẢ sản phẩm
const updatedProducts = allProducts.map(product => {
  const currentPrice = product.current_price || 0;
  const displayPrice = Math.round(currentPrice * (1 - discountPercent / 100));

  return {
    json: {
      sku: product.sku,
      hasEvent: true,
      eventDiscount: true,
      eventInfo: {
        name: event.name || event.event_name || 'Sự kiện ưu đãi',
        discount_percent: discountPercent,
        start_date: event.start_date || '',
        end_date: event.end_date || ''
      },
      display_price: displayPrice,
      discount_percent: discountPercent,
      isVIP: true,
      member_level: 'event',
      original_price: currentPrice,
      new_price: displayPrice
    }
  };
});

return updatedProducts;

// Lấy dữ liệu từ node trước (Check Event Logic)
const inputData = $input.first().json;
const body = inputData.body || {};
const sku = body.SKU || inputData.sku || "Unknown";

// Lấy thông tin event
const event = inputData.event;

// Lấy giá sản phẩm từ database (sẽ được truyền từ node Get Product Price)
const productData = $input.first().json;
const currentPrice = productData.current_price || body.currentPrice || 0;

// Nếu không có event hoặc dữ liệu lỗi, trả về giá gốc
if (!event || !inputData.hasEvent) {
  return [{
    json: {
      sku: sku,
      hasEvent: false,
      eventDiscount: false,
      eventInfo: null,
      display_price: currentPrice,
      discount_percent: 0,
      isVIP: false,
      member_level: 'none'
    }
  }];
}

// Tính toán mức giảm giá
const discountPercent = event.discount_percent || 0;
const displayPrice = Math.round(currentPrice * (1 - discountPercent / 100));

// Trả về kết quả cuối cùng đã áp dụng giảm giá
return [{
  json: {
    sku: sku,
    hasEvent: true,
    eventDiscount: true,
    eventInfo: {
      name: event.name || event.event_name || 'Sự kiện ưu đãi',
      discount_percent: discountPercent,
      start_date: event.start_date || '',
      end_date: event.end_date || ''
    },
    display_price: displayPrice,
    discount_percent: discountPercent,
    isVIP: true,
    member_level: 'event'
  }
}];
